// CLX Email Scraper v3 — Run summary (fires once Split In Batches is done)

const items = $input.all();
const processed = items.length;
const dryRun = $('Config').first().json.dry_run;

console.log('[clx-email-scraper] Run complete. Processed ' + processed + ' leads this run. dry_run=' + dryRun);

return {
  json: {
    workflow: 'clx-email-scraper-v3',
    processed_count: processed,
    dry_run: dryRun,
    finished_at: new Date().toISOString()
  }
};

// CLX Email Scraper v3 — Prep Update Homepage

const item = $input.item.json || {};
const dryRun = $('Config').first().json.dry_run;

const body = {
  p_lead_id: item.id,
  p_fields: {
    email: item.email,
    email_enriched: true,
    email_enriched_at: new Date().toISOString()
  }
};

if (dryRun) {
  console.log('[clx-email-scraper] DRY RUN — would write: ' + JSON.stringify({ lead_id: item.id, email: item.email, path: 'homepage' }));
} else {
  console.log('[clx-email-scraper] PREP UPDATE: ' + JSON.stringify({ lead_id: item.id, email: item.email || 'none', path: 'homepage' }));
}

return {
  json: {
    id: item.id,
    email: item.email,
    rpc_body: body
  }
};

