// CLX Email Scraper v3 — Check RPC result and log errors to scan_errors

const response = $input.item.json;

// Identify which lead was processed (try each Prep Update path)
let leadId = 'unknown';
try { leadId = $('Prep Update Homepage').first().json.id; } catch(e) {}
if (leadId === 'unknown') try { leadId = $('Prep Update Contact').first().json.id; } catch(e) {}
if (leadId === 'unknown') try { leadId = $('Prep Update No Email').first().json.id; } catch(e) {}

// Detect error in Supabase RPC response
const responseStr = JSON.stringify(response);
const isError = !!(response.error || response.message || (response.code && response.code !== '200'));

if (isError) {
  console.log('[clx-email-scraper] RPC FAILED lead=' + leadId + ' response=' + responseStr.substring(0, 300));
  return {
    json: {
      rpc_error: true,
      error_body: JSON.stringify({
        lead_id: leadId,
        error_code: 'scraper_write_failed',
        error_message: responseStr.substring(0, 500),
        created_at: new Date().toISOString()
      })
    }
  };
}

console.log('[clx-email-scraper] RPC OK lead=' + leadId);
return { json: { rpc_error: false, lead_id: leadId } };
